-- Bodyweight Reverse Lunge (bodyweight-reverse-lunge) [merge]
UPDATE coaching.exercise SET
  name = 'Bodyweight Reverse Lunge',
  description = 'Perform Bodyweight Reverse Lunge as controlled resistance work. The athlete uses bodyweight leverage to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.',
