-- Assisted Single-Leg Squat to Box (assisted-single-leg-squat-to-box) [insert]
UPDATE coaching.exercise SET
  name = 'Assisted Single-Leg Squat to Box',
  description = 'Perform Assisted Single-Leg Squat to Box as controlled resistance work. The athlete uses bodyweight leverage to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.',
