  coach_language = 'Primary subrole: squat / knee / dominant / strength. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Assisted Single-Leg Squat to Box as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.',
  athlete_language = 'Set position first, control the hard range, then finish every rep like you could repeat it cleanly.',
  movement_family = 'Single-leg squat progression',
  primary_phase_key = 'capacity',
  phase_subrole = 'squat_knee_dominant_strength',
  primary_order_slot = 'assisted_single_leg_squat_to_box_strength',
  default_sets = 3,
  default_reps = 5,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 30,
