  coaching_execution = '{"movement_description":"Assisted Single-Leg Squat to Box uses bodyweight leverage to train assisted single-leg squat pattern to a box that builds high-leverage leg strength with a safe target.","setup":["Use a stable box or bench that does not slide and matches the athlete''s current range.","Use a clear wall space and keep the area around the athlete free of traffic.","Have the athlete stand on one leg in front of a box and use a wall, post, or light fingertip support as needed.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Assisted Single-Leg Squat to Box.","Sit to the box with control, keep the knee tracking, then stand using the working leg.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Knees track with toes.","Brace and breathe."],"athlete_cues":["Stay organized.","Control down.","Strong finish.","Stop before it gets ugly."],"breathing_cues":["Inhale before the hard portion.","Brace without locking the throat.","Exhale through the finish or during the hold without losing shape."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set."],"quality_gate":["No pain.","Start and finish positions match.","Band path or body line stays repeatable.","Final rep or final five seconds stays clean."],"stop_signs":["Pain appears or increases.","Technique changes more than one rep in a row.","Band anchor slips, grip fails, or support surface moves.","Breathing becomes dizziness, panic bracing, or uncontrolled breath holding."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Accessory strength","Resilience trunk or joint-control work","Conditioning placed later if quality remains high"],"pairs_well_after":["General warm-up","Pattern-specific mobility","Low-fatigue activation or technical rehearsal"],"good_for_sessions":["squat_prep","lower_body_strength"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears or increases during the movement.","Athlete cannot maintain the required joint alignment or trunk position.","Breathing becomes breath-holding panic instead of controlled bracing.","The session priority is fresh speed, jumping, or skill work and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex band/body-resistance demo recommended","Vortex Exercise Card Authoring Guide: Card v2 phase, taxonomy, dosage, scaling, and safety rules","NSCA-style resistance training technique standards"],"internal_notes":["Film Assisted Single-Leg Squat to Box from front/side or anchor-line angle as appropriate.","Show one regression, the standard version, and one progression.","Keep resistance intent clear; do not program as HIIT unless authored as a separate Sustained Capacity card."]}'::jsonb,
