-- Bodyweight Single-Leg RDL Reach (bodyweight-single-leg-rdl-reach) [insert]
UPDATE coaching.exercise SET
  name = 'Bodyweight Single-Leg RDL Reach',
  description = 'Perform Bodyweight Single-Leg RDL Reach as controlled resistance work. The athlete uses bodyweight leverage to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.',
  card_summary = 'Single-leg hinge that builds posterior-chain strength with pelvis and balance control. Use it when the goal is force production, tissue capacity, and repeatable positions with bands or body resistance rather than machines, free weights, or conditioning volume.',
  coach_language = 'Primary subrole: hinge / posterior / chain / strength. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Bodyweight Single-Leg RDL Reach as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.',
  athlete_language = 'Set position first, control the hard range, then finish every rep like you could repeat it cleanly.',
  movement_family = 'Single-leg hinge strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'hinge_posterior_chain_strength',
  primary_order_slot = 'single_leg_rdl_reach_strength',
  default_sets = 3,
  default_reps = 6,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 30,
  movement_requirements = '{"primary_joint_actions":["single_leg_hip_hinge","pelvis_control","ankle_stability","trunk_bracing"],"primary_tissues":["hamstrings","glutes","foot_intrinsics","spinal_erectors"],"primary_motor_control_demands":["alignment_control","tempo_control","bracing_under_resistance"],"postural_shape":"stacked_rib_pelvis","breathing_demand":"controlled","balance_demand":"single_leg","coordination_demand":"moderate","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Bodyweight Single-Leg RDL Reach uses bodyweight leverage to train single-leg hinge that builds posterior-chain strength with pelvis and balance control.","setup":["Have the athlete stand on one leg with a soft knee and reach the free leg long behind.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Bodyweight Single-Leg RDL Reach.","Hinge forward as the back leg reaches, keep hips square, then return to tall balance.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Hips back, spine long.","Brace and breathe."],"athlete_cues":["Stay organized.","Control down.","Strong finish.","Stop before it gets ugly."],"breathing_cues":["Inhale before the hard portion.","Brace without locking the throat.","Exhale through the finish or during the hold without losing shape."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set."],"quality_gate":["No pain.","Start and finish positions match.","Band path or body line stays repeatable.","Final rep or final five seconds stays clean."],"stop_signs":["Pain appears or increases.","Technique changes more than one rep in a row.","Band anchor slips, grip fails, or support surface moves.","Breathing becomes dizziness, panic bracing, or uncontrolled breath holding."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Accessory strength","Resilience trunk or joint-control work","Conditioning placed later if quality remains high"],"pairs_well_after":["General warm-up","Pattern-specific mobility","Low-fatigue activation or technical rehearsal"],"good_for_sessions":["squat_prep","posterior_chain_strength"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears or increases during the movement.","Athlete cannot maintain the required joint alignment or trunk position.","Breathing becomes breath-holding panic instead of controlled bracing.","The session priority is fresh speed, jumping, or skill work and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex band/body-resistance demo recommended","Vortex Exercise Card Authoring Guide: Card v2 phase, taxonomy, dosage, scaling, and safety rules","NSCA-style resistance training technique standards"],"internal_notes":["Film Bodyweight Single-Leg RDL Reach from front/side or anchor-line angle as appropriate.","Show one regression, the standard version, and one progression.","Keep resistance intent clear; do not program as HIIT unless authored as a separate Sustained Capacity card."]}'::jsonb,
  updated_at = now()
WHERE slug = 'bodyweight-single-leg-rdl-reach';

