UPDATE coaching.exercise SET
  name = 'Band Hip Thrust',
  description = 'Perform Band Hip Thrust as controlled resistance work. The athlete uses band tension to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.',
  card_summary = 'Band-resisted hip-extension pattern that builds glute strength with low spinal motion. Use it when the goal is force production, tissue capacity, and repeatable positions with bands or body resistance rather than machines, free weights, or conditioning volume.',
