-- Decline Push-Up (decline-push-up) [merge]
UPDATE coaching.exercise SET
  name = 'Decline Push-Up',
  description = 'Perform Decline Push-Up as controlled resistance work. The athlete uses bodyweight leverage to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.',
  card_summary = 'Feet-elevated push-up that increases bodyweight pressing demand and shoulder contribution. Use it when the goal is force production, tissue capacity, and repeatable positions with bands or body resistance rather than machines, free weights, or conditioning volume.',
  coach_language = 'Primary subrole: upper / body / push / strength. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Decline Push-Up as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.',
  athlete_language = 'Set position first, control the hard range, then finish every rep like you could repeat it cleanly.',
  movement_family = 'Decline push strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'upper_body_push_strength',
  primary_order_slot = 'decline_push_up_strength',
  default_sets = 3,
  default_reps = 6,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 30,
  movement_requirements = '{"primary_joint_actions":["elbow_flexion_extension","shoulder_horizontal_press","scapular_control","anti_extension_bracing"],"primary_tissues":["upper_pectorals","triceps","anterior_deltoids","serratus_anterior","anterior_core"],"primary_motor_control_demands":["alignment_control","tempo_control","bracing_under_resistance"],"postural_shape":"stacked_rib_pelvis","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Decline Push-Up uses bodyweight leverage to train feet-elevated push-up that increases bodyweight pressing demand and shoulder contribution.","setup":["Use a stable box or bench that does not slide and matches the athlete''s current range.","Have the athlete place feet on a stable box and hands on the floor in a strong plank.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Decline Push-Up.","Lower under control, keep the body line rigid, and press back without hips sagging.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Push the floor or band away with quiet ribs.","Brace and breathe."],"athlete_cues":["Stay organized.","Control down.","Strong finish.","Stop before it gets ugly."],"breathing_cues":["Inhale before the hard portion.","Brace without locking the throat.","Exhale through the finish or during the hold without losing shape."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set."],"quality_gate":["No pain.","Start and finish positions match.","Band path or body line stays repeatable.","Final rep or final five seconds stays clean."],"stop_signs":["Pain appears or increases.","Technique changes more than one rep in a row.","Band anchor slips, grip fails, or support surface moves.","Breathing becomes dizziness, panic bracing, or uncontrolled breath holding."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Accessory strength","Resilience trunk or joint-control work","Conditioning placed later if quality remains high"],"pairs_well_after":["General warm-up","Pattern-specific mobility","Low-fatigue activation or technical rehearsal"],"good_for_sessions":["overhead_prep","upper_body_strength"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears or increases during the movement.","Athlete cannot maintain the required joint alignment or trunk position.","Breathing becomes breath-holding panic instead of controlled bracing.","The session priority is fresh speed, jumping, or skill work and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex band/body-resistance demo recommended","Vortex Exercise Card Authoring Guide: Card v2 phase, taxonomy, dosage, scaling, and safety rules","NSCA-style resistance training technique standards"],"internal_notes":["Film Decline Push-Up from front/side or anchor-line angle as appropriate.","Show one regression, the standard version, and one progression.","Keep resistance intent clear; do not program as HIIT unless authored as a separate Sustained Capacity card."]}'::jsonb,
  updated_at = now()
WHERE slug = 'decline-push-up';

INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, 5, 'primary', 'decline_push_up_strength', pos.order_index,
  FALSE, 3, 3,
  3, 0, 'high'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'capacity'
JOIN coaching.phase_order_slot pos ON pos.key = 'decline_push_up_strength' AND pos.phase_id = sp.id
WHERE e.slug = 'decline-push-up'
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role,
  order_slot = EXCLUDED.order_slot,
  order_index = EXCLUDED.order_index,
  fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required,
  fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  fatigue_cost = EXCLUDED.fatigue_cost,
  technical_complexity = EXCLUDED.technical_complexity,
  impact_level = EXCLUDED.impact_level,
  intensity_ceiling = EXCLUDED.intensity_ceiling;

