-- Wall Handstand Hold (wall-handstand-hold) [merge]
UPDATE coaching.exercise SET
  name = 'Wall Handstand Hold',
  description = 'Perform Wall Handstand Hold as controlled resistance work. The athlete uses bodyweight leverage to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.',
  card_summary = 'Wall-supported inverted hold that builds shoulder, wrist, and trunk strength under body resistance. Use it when the goal is position ownership, joint control, and tissue durability under low-to-moderate resistance with bands or body resistance rather than machines, free weights, or conditioning volume.',
  coach_language = 'Primary subrole: scapular / wrist / hand / support / resilience. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Wall Handstand Hold as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.',
  athlete_language = 'Brace, breathe, and own the position. The rep ends when the shape changes.',
  movement_family = 'Inverted support strength',
  primary_phase_key = 'resilience',
  phase_subrole = 'scapular_wrist_hand_support_resilience',
  primary_order_slot = 'wall_handstand_hold_support_strength',
  default_sets = 3,
  default_reps = NULL,
  default_work_seconds = 20,
  default_rest_seconds = 60,
  est_seconds_per_set = 20,
  movement_requirements = '{"primary_joint_actions":["shoulder_flexion_support","elbow_lockout","wrist_extension_load","anti_extension_bracing"],"primary_tissues":["deltoids","triceps","serratus_anterior","forearm_flexors","anterior_core"],"primary_motor_control_demands":["alignment_control","tempo_control","bracing_under_resistance"],"postural_shape":"stacked_rib_pelvis","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Wall Handstand Hold uses bodyweight leverage to train wall-supported inverted hold that builds shoulder, wrist, and trunk strength under body resistance.","setup":["Use a clear wall space and keep the area around the athlete free of traffic.","Have the athlete place hands on the floor near a wall and walk or kick up only to a position the athlete can control.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Wall Handstand Hold.","Push tall through the shoulders, keep ribs stacked, breathe, and step down before shape breaks.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Push the floor or band away with quiet ribs.","Brace and breathe."],"athlete_cues":["Stay organized.","Control down.","Strong finish.","Stop before it gets ugly."],"breathing_cues":["Inhale before the hard portion.","Brace without locking the throat.","Exhale through the finish or during the hold without losing shape."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set."],"quality_gate":["No pain.","Start and finish positions match.","Band path or body line stays repeatable.","Final rep or final five seconds stays clean."],"stop_signs":["Pain appears or increases.","Technique changes more than one rep in a row.","Band anchor slips, grip fails, or support surface moves.","Breathing becomes dizziness, panic bracing, or uncontrolled breath holding."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Main strength work if used as activation","Cooldown or restore work","Low-skill accessory work"],"pairs_well_after":["General warm-up","Low-level breathing or mobility","Main strength work when used as activation only"],"good_for_sessions":["overhead_prep","upper_body_strength"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears or increases during the movement.","Athlete cannot maintain the required joint alignment or trunk position.","Breathing becomes breath-holding panic instead of controlled bracing.","The session priority is fresh speed, jumping, or skill work and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex band/body-resistance demo recommended","Vortex Exercise Card Authoring Guide: Card v2 phase, taxonomy, dosage, scaling, and safety rules","NSCA-style resistance training technique standards"],"internal_notes":["Film Wall Handstand Hold from front/side or anchor-line angle as appropriate.","Show one regression, the standard version, and one progression.","Keep resistance intent clear; do not program as HIIT unless authored as a separate Sustained Capacity card."]}'::jsonb,
  updated_at = now()
WHERE slug = 'wall-handstand-hold';

