UPDATE coaching.exercise SET
  name = 'Band Row',
  description = 'Perform Band Row as controlled resistance work. The athlete uses band tension to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.',
  card_summary = 'Band-resisted horizontal row that builds upper-back, arm, and postural pulling strength. Use it when the goal is force production, tissue capacity, and repeatable positions with bands or body resistance rather than machines, free weights, or conditioning volume.',
