  description = 'Perform Band Pull-Apart as controlled resistance work. The athlete uses band tension to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.',
  card_summary = 'Simple band-resisted horizontal abduction drill for upper-back and shoulder support strength. Use it when the goal is force production, tissue capacity, and repeatable positions with bands or body resistance rather than machines, free weights, or conditioning volume.',
  coach_language = 'Primary subrole: pull / hang / grip / strength. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Band Pull-Apart as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.',
  athlete_language = 'Set position first, control the hard range, then finish every rep like you could repeat it cleanly.',
  movement_family = 'Upper-back accessory strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'pull_hang_grip_strength',
  primary_order_slot = 'band_pull_apart_strength',
  default_sets = 3,
  default_reps = 12,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 60,
  movement_requirements = '{"primary_joint_actions":["horizontal_abduction","scapular_retraction","thoracic_posture_control"],"primary_tissues":["rear_deltoids","rhomboids","middle_trapezius","rotator_cuff"],"primary_motor_control_demands":["alignment_control","tempo_control","bracing_under_resistance"],"postural_shape":"owned_joint_alignment","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"low","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Band Pull-Apart uses band tension to train simple band-resisted horizontal abduction drill for upper-back and shoulder support strength.","setup":["Inspect the band for wear and set a secure anchor or foot position before the athlete loads it.","Have the athlete hold a light band at chest height with arms straight or softly bent.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Band Pull-Apart.","Pull the band apart by moving hands wide, keep ribs down, and return with control.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Control the band; do not let it control you.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Pull elbows to the target without shrugging.","Brace and breathe."],"athlete_cues":["Stay organized.","Control down.","Strong finish.","Stop before it gets ugly."],"breathing_cues":["Inhale before the hard portion.","Brace without locking the throat.","Exhale through the finish or during the hold without losing shape."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set.","Using a band that is too heavy or anchored at the wrong angle."],"quality_gate":["No pain.","Start and finish positions match.","Band path or body line stays repeatable.","Final rep or final five seconds stays clean."],"stop_signs":["Pain appears or increases.","Technique changes more than one rep in a row.","Band anchor slips, grip fails, or support surface moves.","Breathing becomes dizziness, panic bracing, or uncontrolled breath holding."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Accessory strength","Resilience trunk or joint-control work","Conditioning placed later if quality remains high"],"pairs_well_after":["General warm-up","Pattern-specific mobility","Low-fatigue activation or technical rehearsal"],"good_for_sessions":["overhead_prep","upper_body_strength"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears or increases during the movement.","Athlete cannot maintain the required joint alignment or trunk position.","Breathing becomes breath-holding panic instead of controlled bracing.","The session priority is fresh speed, jumping, or skill work and this would create fatigue first.","Band anchor, band condition, or band path cannot be made safe."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex band/body-resistance demo recommended","Vortex Exercise Card Authoring Guide: Card v2 phase, taxonomy, dosage, scaling, and safety rules","NSCA-style resistance training technique standards"],"internal_notes":["Film Band Pull-Apart from front/side or anchor-line angle as appropriate.","Show one regression, the standard version, and one progression.","Keep resistance intent clear; do not program as HIIT unless authored as a separate Sustained Capacity card."]}'::jsonb,
  updated_at = now()
WHERE slug = 'band-pull-apart';

INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
