)
SELECT e.id, sp.id, 5, 'primary', 'band_pull_apart_strength', pos.order_index,
  FALSE, 3, 3,
  1, 0, 'moderate'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'capacity'
