-- Assisted Pull-Up (assisted-pull-up) [merge]
UPDATE coaching.exercise SET
  name = 'Assisted Pull-Up',
  description = 'Perform Assisted Pull-Up as controlled resistance work. The athlete uses band tension to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.',
