-- Half-Kneeling Pallof Press (half-kneeling-pallof-press) [insert]
UPDATE coaching.exercise SET
  name = 'Half-Kneeling Pallof Press',
  description = 'Perform Half-Kneeling Pallof Press as controlled resistance work. The athlete uses band tension to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.',
  card_summary = 'Half-kneeling band anti-rotation press that builds trunk control with hip and pelvis organization. Use it when the goal is position ownership, joint control, and tissue durability under low-to-moderate resistance with bands or body resistance rather than machines, free weights, or conditioning volume.',
  coach_language = 'Primary subrole: trunk / pelvis / anti / movement / control. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Half-Kneeling Pallof Press as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.',
  athlete_language = 'Brace, breathe, and own the position. The rep ends when the shape changes.',
  movement_family = 'Half-kneeling anti-rotation strength',
  primary_phase_key = 'resilience',
  phase_subrole = 'trunk_pelvis_anti_movement_control',
  primary_order_slot = 'half_kneeling_pallof_press_strength',
  default_sets = 3,
  default_reps = 8,
  default_work_seconds = NULL,
  default_rest_seconds = 60,
  est_seconds_per_set = 32,
  movement_requirements = '{"primary_joint_actions":["anti_rotation_bracing","hip_extension_control","shoulder_horizontal_press"],"primary_tissues":["obliques","transverse_abdominis","glutes","serratus_anterior"],"primary_motor_control_demands":["alignment_control","tempo_control","bracing_under_resistance"],"postural_shape":"stacked_rib_pelvis","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Half-Kneeling Pallof Press uses band tension to train half-kneeling band anti-rotation press that builds trunk control with hip and pelvis organization.","setup":["Inspect the band for wear and set a secure anchor or foot position before the athlete loads it.","Have the athlete anchor a band at chest height and kneel sideways to the anchor with inside or outside knee down.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Half-Kneeling Pallof Press.","Press straight ahead, keep hips square, breathe quietly, and return without letting the band twist you.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Control the band; do not let it control you.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Brace and breathe."],"athlete_cues":["Stay organized.","Control down.","Strong finish.","Stop before it gets ugly."],"breathing_cues":["Inhale before the hard portion.","Brace without locking the throat.","Exhale through the finish or during the hold without losing shape."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set.","Using a band that is too heavy or anchored at the wrong angle."],"quality_gate":["No pain.","Start and finish positions match.","Band path or body line stays repeatable.","Final rep or final five seconds stays clean."],"stop_signs":["Pain appears or increases.","Technique changes more than one rep in a row.","Band anchor slips, grip fails, or support surface moves.","Breathing becomes dizziness, panic bracing, or uncontrolled breath holding."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Main strength work if used as activation","Cooldown or restore work","Low-skill accessory work"],"pairs_well_after":["General warm-up","Low-level breathing or mobility","Main strength work when used as activation only"],"good_for_sessions":["general_warmup","trunk_control","resilience"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears or increases during the movement.","Athlete cannot maintain the required joint alignment or trunk position.","Breathing becomes breath-holding panic instead of controlled bracing.","The session priority is fresh speed, jumping, or skill work and this would create fatigue first.","Band anchor, band condition, or band path cannot be made safe."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex band/body-resistance demo recommended","Vortex Exercise Card Authoring Guide: Card v2 phase, taxonomy, dosage, scaling, and safety rules","NSCA-style resistance training technique standards"],"internal_notes":["Film Half-Kneeling Pallof Press from front/side or anchor-line angle as appropriate.","Show one regression, the standard version, and one progression.","Keep resistance intent clear; do not program as HIIT unless authored as a separate Sustained Capacity card."]}'::jsonb,
  updated_at = now()
WHERE slug = 'half-kneeling-pallof-press';

