UPDATE coaching.exercise SET
  name = 'Tall-Kneeling Band Chop',
  description = 'Perform Tall-Kneeling Band Chop as controlled resistance work. The athlete uses band tension to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.',
  card_summary = 'Tall-kneeling diagonal band chop that builds controlled rotation, anti-rotation braking, and trunk-hip linkage. Use it when the goal is position ownership, joint control, and tissue durability under low-to-moderate resistance with bands or body resistance rather than machines, free weights, or conditioning volume.',
  coach_language = 'Primary subrole: trunk / pelvis / anti / movement / control. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Tall-Kneeling Band Chop as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.',
  athlete_language = 'Brace, breathe, and own the position. The rep ends when the shape changes.',
  movement_family = 'Controlled rotational trunk strength',
  primary_phase_key = 'resilience',
  phase_subrole = 'trunk_pelvis_anti_movement_control',
