  coaching_execution = '{"movement_description":"Tall-Kneeling Band Chop uses band tension to train tall-kneeling diagonal band chop that builds controlled rotation, anti-rotation braking, and trunk-hip linkage.","setup":["Inspect the band for wear and set a secure anchor or foot position before the athlete loads it.","Have the athlete anchor a band high and kneel tall sideways or slightly angled to the anchor.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Tall-Kneeling Band Chop.","Pull the band diagonally across the body, rotate only through owned range, then return slowly.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Control the band; do not let it control you.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Pull elbows to the target without shrugging.","Brace and breathe."],"athlete_cues":["Stay organized.","Control down.","Strong finish.","Stop before it gets ugly."],"breathing_cues":["Inhale before the hard portion.","Brace without locking the throat.","Exhale through the finish or during the hold without losing shape."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set.","Using a band that is too heavy or anchored at the wrong angle."],"quality_gate":["No pain.","Start and finish positions match.","Band path or body line stays repeatable.","Final rep or final five seconds stays clean."],"stop_signs":["Pain appears or increases.","Technique changes more than one rep in a row.","Band anchor slips, grip fails, or support surface moves.","Breathing becomes dizziness, panic bracing, or uncontrolled breath holding."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Main strength work if used as activation","Cooldown or restore work","Low-skill accessory work"],"pairs_well_after":["General warm-up","Low-level breathing or mobility","Main strength work when used as activation only"],"good_for_sessions":["general_warmup","trunk_control","resilience"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears or increases during the movement.","Athlete cannot maintain the required joint alignment or trunk position.","Breathing becomes breath-holding panic instead of controlled bracing.","The session priority is fresh speed, jumping, or skill work and this would create fatigue first.","Band anchor, band condition, or band path cannot be made safe."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex band/body-resistance demo recommended","Vortex Exercise Card Authoring Guide: Card v2 phase, taxonomy, dosage, scaling, and safety rules","NSCA-style resistance training technique standards"],"internal_notes":["Film Tall-Kneeling Band Chop from front/side or anchor-line angle as appropriate.","Show one regression, the standard version, and one progression.","Keep resistance intent clear; do not program as HIIT unless authored as a separate Sustained Capacity card."]}'::jsonb,
