JOIN coaching.exercise e ON e.slug = v.slug
WHERE NOT EXISTS (
  SELECT 1 FROM coaching.exercise_scaling_profile sp
  WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum'
);

-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and force/tissue capacity for band and body-resistance work in the Capacity or Resilience phase.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('tempo-bodyweight-squat', 'It lets coaches make a basic squat strength-focused by adding tempo, pauses, and strict depth quality. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('band-resisted-squat', 'Band tension adds force demand while keeping loading scalable for youth, team, and home-gym environments. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('prisoner-squat', 'The prisoner arm position exposes trunk collapse and makes posture part of the strength problem. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('bodyweight-box-squat', 'The box gives a clear range target and makes the athlete control both the descent and restart. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('bodyweight-split-squat', 'It delivers unilateral force production with minimal setup and clear scaling by range, tempo, and support. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('rear-foot-elevated-split-squat', 'The elevation shifts more work to the front leg and creates a powerful lower-body strength stimulus without external load. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('bodyweight-reverse-lunge', 'Reverse stepping usually reduces forward knee shear while still training one-leg force production and alignment. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('bodyweight-lateral-lunge', 'It fills a gap left by straight-line squat work by loading lateral hip and adductor strength through owned range. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('bodyweight-step-up', 'It develops practical step-up strength while letting coaches adjust box height to match available range. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('assisted-single-leg-squat-to-box', 'The box and support make a hard single-leg strength skill coachable without forcing sloppy depth. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('bodyweight-hip-hinge-good-morning', 'It turns the hinge into a repeatable strength pattern by emphasizing long-spine control, hamstring tension, and hip drive. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('banded-good-morning', 'The band adds resistance through hip extension while still keeping the hinge easy to set up and regress. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('bodyweight-single-leg-rdl-reach', 'The long-lever reach loads the posterior chain while forcing the athlete to own hip, foot, and trunk position. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('band-hip-thrust', 'The band loads hip extension directly and gives a strong glute stimulus without heavy external implements. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('bodyweight-glute-bridge', 'It is a low-barrier posterior-chain strength option for athletes who need hip extension without standing balance demand. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('single-leg-glute-bridge', 'It upgrades the basic bridge into a more meaningful unilateral strength task without adding equipment. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('banded-hamstring-curl', 'It isolates knee-flexion strength that supports sprinting, hinging, and deceleration without needing machines. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Capacity because the main adaptation is progressive resistance, force production, and tissue capacity.', 'Use in the Capacity phase after Prepare & Access and any true Output work. Keep it before hard conditioning; pair with enough rest that band tension, body position, and rep quality stay strength-focused.', 'The common mistake is chasing reps, band tension, or speed after position quality drops. This should build strength and tissue capacity, not become a burnout circuit before skill, speed, or power work.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
  ('nordic-hamstring-eccentric', 'The slow eccentric gives a high hamstring stimulus and should be managed like tissue-capacity work, not conditioning. Band and body-resistance training works when the athlete controls leverage, tempo, and alignment instead of relying on momentum. This creates usable force, tissue tolerance, and position ownership with low impact and minimal equipment.', 'Belongs in Resilience because the main adaptation is control, bracing, joint ownership, and tissue durability under manageable resistance.', 'Use in the Resilience phase after main Capacity work, or earlier only when the dose is low and the goal is activation/control rather than fatigue. Stop the set when bracing, alignment, or breathing quality drops.', 'The common mistake is turning a control drill into a long, shaky endurance test. Use enough resistance to challenge position, but stop before breath-holding, compensation, or joint discomfort becomes the training effect.', 'Scale first by leverage, support, range of motion, band thickness, tempo, hold duration, and rest. Progress only when the athlete can keep pain-free range, clean alignment, steady breathing, and repeatable reps.'),
